const MANAGED_BY = 'google-contact-birthday-sync';
const CALENDAR_ID = '9b70507aba42b687815ea7e0291431e150247a15d3ba1b4dda66fb9dc888f259@group.calendar.google.com';
const TIMEZONE = 'Europe/Berlin';
const pages = $input.all();

function pad(value) {
  return String(value).padStart(2, '0');
}

function isLeapYear(year) {
  return (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;
}

function nextDate(dateString) {
  const [year, month, day] = dateString.split('-').map(Number);
  const date = new Date(Date.UTC(year, month - 1, day));
  date.setUTCDate(date.getUTCDate() + 1);
  return [date.getUTCFullYear(), pad(date.getUTCMonth() + 1), pad(date.getUTCDate())].join('-');
}

function chooseName(person) {
  const names = person.names ?? [];
  const preferred = names.find((entry) => entry.metadata?.primary) ?? names[0];
  return preferred?.displayName?.trim() || null;
}

function chooseBirthday(person) {
  const birthdays = (person.birthdays ?? [])
    .filter((entry) => entry.date?.month && entry.date?.day)
    .sort((left, right) => {
      const leftScore = left.metadata?.primary ? 0 : 1;
      const rightScore = right.metadata?.primary ? 0 : 1;
      return leftScore - rightScore;
    });
  return birthdays[0] ?? null;
}

const currentYear = new Date().getFullYear();
const targetYears = [currentYear, currentYear + 1];
const desiredEvents = [];
const seenKeys = new Set();
let contactsWithBirthdays = 0;

for (const page of pages) {
  const connections = page.json.connections ?? [];
  for (const person of connections) {
    const contactKey = person.resourceName;
    const name = chooseName(person);
    const birthday = chooseBirthday(person);
    if (!contactKey || !name || !birthday?.date?.month || !birthday?.date?.day) {
      continue;
    }

    contactsWithBirthdays += 1;
    const birthYear = Number.isInteger(birthday.date.year) ? birthday.date.year : null;
    const month = birthday.date.month;
    const day = birthday.date.day;

    for (const eventYear of targetYears) {
      if (month === 2 && day === 29 && !isLeapYear(eventYear)) {
        continue;
      }

      const eventKey = `${contactKey}::${eventYear}`;
      if (seenKeys.has(eventKey)) {
        continue;
      }
      seenKeys.add(eventKey);

      const startDate = `${eventYear}-${pad(month)}-${pad(day)}`;
      const age = birthYear !== null ? eventYear - birthYear : null;
      const summary = age !== null ? `${name} Birthday (${age})` : `${name} Birthday`;

      desiredEvents.push({
        eventKey,
        contactKey,
        eventYear: String(eventYear),
        summary,
        startDate,
        endDate: nextDate(startDate),
        description: `Managed by ${MANAGED_BY}. Source contact: ${contactKey}`,
        privateProperties: {
          managedBy: MANAGED_BY,
          contactKey,
          eventYear: String(eventYear),
        },
      });
    }
  }
}

desiredEvents.sort((left, right) => left.startDate.localeCompare(right.startDate) || left.summary.localeCompare(right.summary));

return [{
  json: {
    managedBy: MANAGED_BY,
    calendarId: CALENDAR_ID,
    timezone: TIMEZONE,
    windowStart: `${currentYear}-01-01T00:00:00Z`,
    windowEnd: `${currentYear + 2}-01-01T00:00:00Z`,
    targetYears,
    contactsWithBirthdays,
    desiredEventCount: desiredEvents.length,
    desiredEvents,
  },
}];

const summary = $('Normalize Contact Birthdays').first().json;
const pages = $input.all();
const existingEvents = [];
for (const page of pages) {
  for (const event of page.json.items ?? []) {
    existingEvents.push(event);
  }
}

const reminderMinutes = 10 * 60;

function buildBody(desired) {
  return {
    summary: desired.summary,
    description: desired.description,
    start: { date: desired.startDate },
    end: { date: desired.endDate },
    extendedProperties: { private: desired.privateProperties },
    reminders: {
      useDefault: false,
      overrides: [
        {
          method: 'popup',
          minutes: reminderMinutes,
        },
      ],
    },
  };
}

function hasMatchingReminder(existing) {
  const reminders = existing.reminders ?? {};
  const overrides = reminders.overrides ?? [];
  return reminders.useDefault === false
    && overrides.length === 1
    && overrides[0]?.method === 'popup'
    && overrides[0]?.minutes === reminderMinutes;
}

function isEquivalent(existing, desired) {
  const privateProps = existing.extendedProperties?.private ?? {};
  return existing.summary === desired.summary
    && existing.description === desired.description
    && existing.start?.date === desired.startDate
    && existing.end?.date === desired.endDate
    && privateProps.managedBy === desired.privateProperties.managedBy
    && privateProps.contactKey === desired.privateProperties.contactKey
    && privateProps.eventYear === desired.privateProperties.eventYear
    && hasMatchingReminder(existing);
}

const existingByKey = new Map();
for (const event of existingEvents) {
  const privateProps = event.extendedProperties?.private ?? {};
  if (privateProps.managedBy !== summary.managedBy || !privateProps.contactKey || !privateProps.eventYear) {
    continue;
  }
  existingByKey.set(`${privateProps.contactKey}::${privateProps.eventYear}`, event);
}

const actions = [];
for (const desired of summary.desiredEvents) {
  const existing = existingByKey.get(desired.eventKey);
  if (!existing) {
    actions.push({
      json: {
        operation: 'create',
        method: 'POST',
        url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(summary.calendarId)}/events`,
        body: buildBody(desired),
        eventKey: desired.eventKey,
        summary: desired.summary,
      },
    });
    continue;
  }

  if (!isEquivalent(existing, desired)) {
    actions.push({
      json: {
        operation: 'update',
        method: 'PATCH',
        url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(summary.calendarId)}/events/${encodeURIComponent(existing.id)}`,
        body: buildBody(desired),
        eventKey: desired.eventKey,
        summary: desired.summary,
        existingEventId: existing.id,
      },
    });
  }
}

const desiredKeys = new Set(summary.desiredEvents.map((entry) => entry.eventKey));
for (const [eventKey, existing] of existingByKey.entries()) {
  if (desiredKeys.has(eventKey)) {
    continue;
  }
  actions.push({
    json: {
      operation: 'delete',
      method: 'DELETE',
      url: `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(summary.calendarId)}/events/${encodeURIComponent(existing.id)}`,
      eventKey,
      summary: existing.summary,
      existingEventId: existing.id,
    },
  });
}

return actions;
